checker_dsl:
EXISTS (`method sub`, `method sup`) {
  AND {
    (`sub overrides sup`),
    (`sup is declared as synchronized`),
    NOT { (`sub is declared as synchronized`) },
    NOT {
      EXISTS (`statement stmt`) {
        OR {
          EXISTS (`expression expr1`, `method call call`) {
            AND {
              (`call is expr1`),
              (`the qualifier of call is a super access`),
              (`the callee of call is sup`),
              FORALL (`expression arg`) {
                AND {
                  (`arg is an argument of call`),
                  (`arg is a variable access`)
                }
              }
            }
          },
          EXISTS (`expression expr2`, `method call call`) {
            AND {
              (`call is expr2`),
              (`the qualifier of call is a super access`),
              (`the callee of call is sup`),
              FORALL (`expression arg`) {
                AND {
                  (`arg is an argument of call`),
                  (`arg is a variable access`)
                }
              }
            }
          },
          EXISTS (`expression expr3`, `casting expression castExpr`, `expression innerExpr`, `method call call`) {
            AND {
              (`call is innerExpr`),
              (`the qualifier of call is a super access`),
              (`the callee of call is sup`),
              FORALL (`expression arg`) {
                AND {
                  (`arg is an argument of call`),
                  (`arg is a variable access`)
                }
              }
            }
          },
          EXISTS (`expression expr4`, `casting expression castExpr`, `expression innerExpr`, `method call call`) {
            AND {
              (`call is innerExpr`),
              (`the qualifier of call is a super access`),
              (`the callee of call is sup`),
              FORALL (`expression arg`) {
                AND {
                  (`arg is an argument of call`),
                  (`arg is a variable access`)
                }
              }
            }
          }
        }
      }
    }
  }
}
